div.font:
variable "users" = {
alice = { tags = { Role = "Lead" } }
bob = { tags = { Role = "Dev" } }
eve = { tags = { Role = "Audit" } }
}

data "aws_ami" "ubuntu" {
most_recent = true
owners = ["099720109477"] # Canonical
filter { name = "name" values = ["ubuntu/images/hvm-ssd-gp3/ubuntu-noble-24.04-arm64-server-*"] }
}
data.aws_ami.ubuntu.id → resuelto en plan (no en apply)

resource "aws_launch_template" "app" {
name_prefix = "${var.project}-lt-"
image_id = data.aws_ami.ubuntu.id
instance_type = "t4g.micro"
lifecycle {
create_before_destroy = true
}
}

output "user_arns" {
value = {
for k, u in aws_iam_user.team : k => u.arn
}
}
Resultado: { alice = arn:..., bob = arn:..., eve = arn:... }
